var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"말도 안 돼. CRF로 내 존재자체에 간섭한다고…?","JPN":"ありえない。CRFで私の存在自体に干渉してくるだなんて……？","ENG":"Impossible... you are interfering with my very existence using CRF...?","TWN":"這不可能，居然用CRF干涉我的存在…？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN"},{"id":"L3_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"대체 뭐야, 이 검술은…!!","JPN":"いったい何なの、この剣術……！！","ENG":"What on earth is this sword art...?!!","TWN":"到底怎麼回事？這劍術…！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"나나하라류의 본질은 혼백을 베어내는 명부신의 검술.","JPN":"七原流の本質は魂魄を切り裂く冥府の神の剣術。","ENG":"The essence of the Nanahara Style is the Nether God's swordsmanship that cleaves souls.","TWN":"七原流的本質是斬斷魂魄的冥府神劍術。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"이승을 허망히 떠도는 그림자가 제 묘에 눕길 거부한다면…….","JPN":"ただ虚しく現世を彷徨う影が、己の墓に入ることを拒否するなら……","ENG":"If a Shadow wandering this world refuses to lie in its proper grave...","TWN":"如果在凡間遊蕩的暗影拒絕躺在我的墳上……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"억지로 일으킨 운명을 내 검으로 끊어주마.","JPN":"強引に呼び起こしたその運命を、私の刀で断つ。","ENG":"...then I'll sever that forcibly-raised fate with my blade.","TWN":"我要用我的劍斬斷強行掀起的命運。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L15_1","type":"dialog","speaker":"LEADER_NPC_NANAHARA2_NULL","text":{"KOREA":"엄폐하면서 밀어붙여! 사도들을 한 놈도 살려두지 마라!","JPN":"隠蔽しながら追い込め！　使徒を1匹たりとも逃がすな！","ENG":"Push up under cover! Leave not a single Apostle alive!","TWN":"一邊掩護一邊推進！別放過任何一個使徒！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_SL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L18_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"중장님, 이분들은 분명…….","JPN":"中将、この方々は……","ENG":"Lieutenant General, these people are surely...","TWN":"中將，這些人肯定……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그래. 관리국 쪽 지원이 도착한 모양이군.","JPN":"ああ。管理局からの支援さ。","ENG":"Yes. Looks like support from the Administration has arrived.","TWN":"很好，看來管理局那邊的支援到了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"아무래도… 우리 명줄이 제법 긴 모양이야.","JPN":"どうやら……我々はまだ死ねないようだ。","ENG":"It seems... our lifeline's a fair bit longer than we thought.","TWN":"不管怎麼說…看來我們的命還真大。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SANAE_NANA_NULL_PR","text":{"KOREA":"고르디우스 전대 일동, 주인어른께서 말씀하신 델타 세븐 대원분들과 합류했습니다.","JPN":"ゴルディウス戦隊一同、社長に言われた通り、デルタセブンの隊員と合流しました。","ENG":"Gordias Division here. Per Master's orders, we've met up with the Delta Seven members.","TWN":"哥帝爾斯戰隊全體隊員，和主人說過的第七三角洲隊員會合了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_PR","text":{"KOREA":"이쪽은 저희가 맡을 터이니, 나오 님 일행께서는 대균열 쪽에 힘써주시길.","JPN":"こちらは私たちにお任せください。ナオ様のほうは大亀裂をお願いします。","ENG":"We'll handle things on this side. Miss Nao, please focus your party on the Grand Dimension Crevice.","TWN":"這裡就由我們來負責，請奈緒一行人幫幫大峽谷那邊的忙。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래. 그쪽은 믿고 맡기마.","JPN":"ああ、そちらはお主に任せよう。","ENG":"Right. I'm leaving this to you.","TWN":"好，就交給你們了。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"부탁한다, 사나에.","JPN":"頼んだぞ、早苗。","ENG":"I'm counting on you, Sanae.","TWN":"拜託妳了，早苗。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"지금 막 전대원들을 태운 카미이즈미가 현장에 도착했다.","JPN":"たった今、戦隊員を乗せた上泉が現場に着いたんじゃ。","ENG":"Kamiizumi has just arrived on-site with the division members aboard.","TWN":"載著全體隊員的上泉剛抵達現場。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"사나에와 당주 자매들이 있으니, 저쪽 현장은 신경 쓸 필요 없겠지.","JPN":"早苗と当主姉妹がいるから、向こうの現場は心配せんでよいじゃろう。","ENG":"With you and the Lady Nanahara's sisters there, we shouldn't have to worry about that front.","TWN":"有早苗和堂主姐妹們在，應該不用擔心那邊的現場吧。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저기-. 그런데 이 바바 야가. 제대로 가고 있는 거 맞나요?","JPN":"あの～ところでこのバーバ・ヤーガ、ちゃんと目的地に向かってるんですか？","ENG":"Hey, about this Baba Yaga. Are we actually headed the right way?","TWN":"那個–但是這個芭芭雅嘎，有在前進沒錯嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이제 와서 하는 말이지만…….","JPN":"今更だけど……","ENG":"Hate to say this now, but...","TWN":"雖然現在才這麼說……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L37_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"쟤가 운전하는 게 영 불안한데.","JPN":"あいつが運転って、不安しかないんですけど。","ENG":"I don't love the idea of that one doing the flying. Kinda nervous here.","TWN":"但它駕駛讓我覺得很不安。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"폭실이 엄청 똑똑해요.","JPN":"モコはとっても賢いんです。","ENG":"Fluffox is super smart.","TWN":"福實非常聰明。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L42_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"걱정 마. 저래 보여도 북방합의체의 최신 기술이 반영된 모델이야.","JPN":"大丈夫よ。ああ見えて北方合意体の最新技術が反映されたモデルだから。","ENG":"Relax. It might not look it, but this model incorporates the latest Northern Union tech.","TWN":"不用擔心，別看它那樣，它可是反映北方和議會最新技術的機型。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"기계한테 자율주행을 맡기는 게 무면허들이 모는 것보단 백배 낫겠지.","JPN":"無免許運転よりは機械の自律走行の方が百倍マシでしょ。","ENG":"Letting the machine auto-pilot is a hundred times better than unlicensed drivers at the stick.","TWN":"交給機器自動駕駛應該比無照駕駛好一百倍。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐야, 너 아직도 있었어?","JPN":"何だ。あなた、まだいたの？","ENG":"Huh? You're still here?","TWN":"搞什麼？妳還在嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"니들이 끌고 와놓고 뭔 소리야? 누군 여기까지 오고 싶어서 온 줄 알아?","JPN":"お前たちが連れてきたくせに何言ってるの？　好きで来てるわけじゃないわ。","ENG":"You dragged me along, what are you on about? You think I wanted to come this far?","TWN":"你們把人拖來這裡之後在說什麼？以為誰想跑來這裡嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"여기 있기 싫으면 뛰어내리면 되잖아.","JPN":"いやなら飛び降りればいいじゃない。","ENG":"If you don't wanna be here, jump out.","TWN":"如果不想待在這裡，跳下去不就好了嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"내가 너처럼 흡혈귀였으면 그랬겠지!","JPN":"私もお前みたいな吸血鬼だったらそうしてたわよ！","ENG":"If I were a vampire like you, maybe I would!","TWN":"要是我像妳一樣是個吸血鬼，早就這麼做了！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"음…….","JPN":"うーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이 조합. 괜찮은 거야?","JPN":"この組み合わせ、大丈夫なの？","ENG":"Is this lineup really okay?","TWN":"這個組合沒問題嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"낸들 아냐. 이미 엎질러진 물이니 어쩔 수 없는 노릇이지.","JPN":"覆水盆に返らず。こうなった以上、突き進むしかないじゃろう。","ENG":"How should I know? The water's already spilled so there's no use crying over it.","TWN":"我怎麼知道？覆水難收了。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"해결해야 할 문제가 산더미다만, 당장은 눈앞의 문제에 집중하자꾸나.","JPN":"解決すべき問題は山積みじゃが、今は目の前の問題に集中するんじゃ。","ENG":"We have mountains to sort out. But for now, eyes on the problem right in front of us.","TWN":"雖然有一堆問題要解決，但還是專注在眼前的問題上吧。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};